INSERT INTO word_questions (day_set, definition, options, answer, explanation) VALUES
(9,  'No longer in use; outdated',                                                     ARRAY['Modern','Ancient','Obsolete','Temporary'],         'Obsolete',      'Obsolete describes something no longer in use or out of date. Technology often becomes obsolete as newer innovations emerge.'),
(10, 'Lasting for only a very short time; fleeting',                                   ARRAY['Permanent','Ephemeral','Eternal','Durable'],        'Ephemeral',     'Ephemeral comes from Greek meaning lasting only a day. It describes things that are fleeting, like a rainbow or a soap bubble.'),
(11, 'Fluent and persuasive in speaking or writing',                                   ARRAY['Verbose','Eloquent','Blunt','Vague'],               'Eloquent',      'Eloquent describes someone who expresses ideas clearly and persuasively. A great orator is often called eloquent.'),
(12, 'Holding firmly to something; persistent and determined',                         ARRAY['Fickle','Passive','Tenacious','Timid'],             'Tenacious',     'Tenacious means persistent and determined. A tenacious person holds on to their goals despite difficulties or opposition.'),
(13, 'Open to more than one interpretation; unclear',                                  ARRAY['Definite','Precise','Ambiguous','Literal'],         'Ambiguous',     'Ambiguous describes something that can be understood in more than one way. Ambiguity often causes confusion in communication.'),
(14, 'Showing great attention to detail; extremely careful and precise',               ARRAY['Careless','Hasty','Meticulous','Casual'],           'Meticulous',    'Meticulous means being extremely careful and precise about details. A meticulous person leaves nothing to chance.'),
(15, 'Dealing with things in a sensible and realistic way; practical',                 ARRAY['Idealistic','Pragmatic','Dreamy','Impractical'],    'Pragmatic',     'Pragmatic means focusing on practical solutions rather than ideals. A pragmatic leader makes decisions based on what actually works.'),
(16, 'Well-meaning and kindly; wishing good to others',                                ARRAY['Malevolent','Selfish','Benevolent','Indifferent'],  'Benevolent',    'Benevolent means kind and generous in nature. A benevolent person or organization acts for the benefit of others.'),
(17, 'Truthful and straightforward; frank and honest',                                 ARRAY['Deceitful','Reserved','Candid','Evasive'],          'Candid',        'Candid means being honest and direct, even when the truth is uncomfortable. A candid conversation leaves nothing hidden.'),
(18, 'Having or showing steady effort and care; hardworking',                          ARRAY['Lazy','Diligent','Reckless','Negligent'],           'Diligent',      'Diligent means working carefully and persistently. A diligent student studies regularly and pays close attention to their work.'),
(19, 'Able to recover quickly from difficulties; tough and adaptable',                 ARRAY['Fragile','Rigid','Weak','Resilient'],               'Resilient',     'Resilient describes the ability to bounce back from adversity. Resilient people adapt and recover when faced with setbacks.'),
(20, 'Showing willingness to take bold risks; daring and fearless',                    ARRAY['Timid','Cautious','Audacious','Hesitant'],          'Audacious',     'Audacious means extremely bold and daring. An audacious plan is one that is ambitious and shows no fear.'),
(21, 'Expressed clearly and easy to understand; coherent',                             ARRAY['Confusing','Vague','Lucid','Complex'],              'Lucid',         'Lucid means perfectly clear and easy to understand. A lucid explanation leaves no room for confusion.'),
(22, 'Refusing to be persuaded or to change one''s mind; unshakeable',                ARRAY['Flexible','Wavering','Adamant','Agreeable'],        'Adamant',       'Adamant means absolutely firm in attitude or opinion. Being adamant means you will not change your position no matter what.'),
(23, 'Using more words than necessary; overly wordy',                                  ARRAY['Concise','Brief','Verbose','Silent'],               'Verbose',       'Verbose means using an excessive number of words. A verbose speaker or writer often loses the audience''s attention.'),
(24, 'Sparing or economical with money; not wasteful',                                 ARRAY['Lavish','Generous','Frugal','Extravagant'],         'Frugal',        'Frugal means being economical and avoiding waste. A frugal person spends money wisely and avoids unnecessary expenses.'),
(25, 'Calm, peaceful, and not easily upset or disturbed',                              ARRAY['Anxious','Turbulent','Agitated','Placid'],          'Placid',        'Placid describes a calm and peaceful disposition. A placid lake has smooth undisturbed water — just like a placid person.'),
(26, 'Having a strong desire to know and learn things; curious',                       ARRAY['Indifferent','Inquisitive','Apathetic','Bored'],    'Inquisitive',   'Inquisitive means curious and eager to learn. An inquisitive mind always asks questions and seeks to understand the world.'),
(27, 'Unconventional and slightly strange in behavior or appearance',                  ARRAY['Normal','Conventional','Eccentric','Ordinary'],    'Eccentric',     'Eccentric describes someone whose behavior or ideas are unusual or odd. Many great artists and thinkers were considered eccentric.'),
(28, 'Giving a warning or sign that something bad is about to happen',                 ARRAY['Promising','Cheerful','Ominous','Bright'],          'Ominous',       'Ominous means suggesting that something bad is going to happen. Dark clouds gathering can be ominous signs of a coming storm.'),
(29, 'Calm, peaceful, and untroubled; utterly tranquil',                               ARRAY['Chaotic','Turbulent','Restless','Serene'],          'Serene',        'Serene means perfectly calm and at peace. A serene environment like a quiet mountain lake brings a sense of deep calm.'),
(30, 'Producing many works, results, or ideas; highly productive',                    ARRAY['Barren','Idle','Prolific','Scarce'],                'Prolific',      'Prolific means producing a great amount. A prolific writer publishes many books; a prolific inventor creates countless innovations.'),
(31, 'Generous and forgiving, especially toward a rival or enemy',                     ARRAY['Petty','Spiteful','Magnanimous','Cruel'],           'Magnanimous',   'Magnanimous means noble and generous in spirit. A magnanimous winner praises their opponent and shows no bitterness in victory.'),
(32, 'Not telling the truth; habitually dishonest and deceptive',                      ARRAY['Honest','Truthful','Sincere','Mendacious'],         'Mendacious',    'Mendacious means given to lying or deception. A mendacious person cannot be trusted because they habitually tell untruths.'),
(33, 'Wanting or devouring great quantities; extremely eager or greedy',               ARRAY['Moderate','Indifferent','Voracious','Satisfied'],   'Voracious',     'Voracious means having a very strong appetite for something whether food reading or knowledge. A voracious reader finishes books in one sitting.'),
(34, 'Having or showing keen mental judgment and wisdom',                              ARRAY['Foolish','Naive','Reckless','Sagacious'],           'Sagacious',     'Sagacious means wise with the ability to make good judgments. A sagacious leader makes decisions based on insight and experience.'),
(35, 'Difficult to interpret or understand; mysterious and puzzling',                  ARRAY['Obvious','Clear','Enigmatic','Simple'],             'Enigmatic',     'Enigmatic means mysterious and difficult to understand. The Mona Lisa''s smile is often described as enigmatic.'),
(36, 'Tending to talk a great deal; extremely talkative',                              ARRAY['Reserved','Quiet','Loquacious','Taciturn'],         'Loquacious',    'Loquacious means talking a lot. A loquacious person can speak on any topic at length and often dominates conversations.'),
(37, 'Brisk and cheerful readiness or willingness to do something',                   ARRAY['Reluctance','Alacrity','Laziness','Hesitation'],    'Alacrity',      'Alacrity means eager and enthusiastic willingness. When asked to do something enjoyable people often respond with alacrity.'),
(38, 'A person who flatters important people to gain personal advantage',              ARRAY['Critic','Sycophant','Mentor','Adversary'],          'Sycophant',     'A sycophant uses excessive flattery to gain favour. Also called a yes-man they agree with everything a powerful person says.'),
(39, 'More than what is necessary or useful; excessive and redundant',                 ARRAY['Essential','Necessary','Required','Superfluous'],   'Superfluous',   'Superfluous means unnecessary or excessive. Removing superfluous words from a sentence makes it clearer and more powerful.'),
(40, 'Reserved or uncommunicative in speech; saying very little',                      ARRAY['Chatty','Loquacious','Taciturn','Sociable'],        'Taciturn',      'Taciturn describes someone who speaks very little. A taciturn person expresses feelings through action rather than words.'),
(41, 'Avoiding activity; having a dislike of work; habitually lazy',                   ARRAY['Active','Diligent','Energetic','Indolent'],         'Indolent',      'Indolent means avoiding work or exertion. An indolent person prefers rest and idleness over productive activity.'),
(42, 'Having a ready insight into things; keenly perceptive and shrewd',               ARRAY['Oblivious','Naive','Perspicacious','Clueless'],     'Perspicacious', 'Perspicacious means having sharp insight and understanding. A perspicacious observer notices details and patterns others easily miss.'),
(43, 'Going beyond what is considered proper or appropriate; arrogantly bold',         ARRAY['Cautious','Uncertain','Presumptuous','Humble'],     'Presumptuous',  'Presumptuous means behaving with too much confidence or entitlement often overstepping boundaries or assuming something without permission.');
